import { initializeApp } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-app.js";
import { getAuth, signOut, onAuthStateChanged } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { getFirestore, collection, doc, setDoc, getDoc, onSnapshot, getDocs, updateDoc, increment, addDoc, deleteDoc, query, limit } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

const firebaseConfig={apiKey:"AIzaSyDw3v36LdOJwGMJaz5S4XcWnNU0fWtYDKs",authDomain:"verdant-d9d31.firebaseapp.com",projectId:"verdant-d9d31",storageBucket:"verdant-d9d31.firebasestorage.app",messagingSenderId:"436266438871",appId:"1:436266438871:web:3e021d2337c030b28de092"};
const app=initializeApp(firebaseConfig);const auth=getAuth(app);const db=getFirestore(app);

function getLocalCart(){const c=localStorage.getItem('verdant_cart');return c?JSON.parse(c):[];}
function saveLocalCart(c){localStorage.setItem('verdant_cart',JSON.stringify(c));updateCartBadge();}
function addToLocalCart(p,q){const c=getLocalCart();const e=c.find(i=>i.id===p.id);if(e)e.qty+=q;else c.push({...p,qty:q});saveLocalCart(c);}
function clearLocalCart(){localStorage.removeItem('verdant_cart');updateCartBadge();}
function updateCartBadge(){const c=getLocalCart();const t=c.reduce((a,i)=>a+i.qty,0);const b=document.getElementById('cart-badge');if(b)b.textContent=t>0?`(${t})`:'';}

function setupNavbar(){
    const nav=document.getElementById('navbar');if(!nav)return;
    onAuthStateChanged(auth,async(user)=>{
        let links=`<a href="index.html" class="nav-link">Home</a><a href="products.html" class="nav-link">Shop</a>`;
        if(user){
            links+=`<a href="admin.html" class="nav-link">Dashboard</a><a href="add-plant.html" class="nav-link">Add Plant</a><a href="checkout.html" class="nav-link">Cart <span id="cart-badge"></span></a><button id="logout-btn" class="nav-link" style="background:none;font-size:inherit;color:inherit;cursor:pointer;">Logout</button>`;
            nav.innerHTML=`<a href="index.html" class="nav-brand">🪴 Verdant</a><div class="nav-links">${links}</div>`;
            document.getElementById('logout-btn').addEventListener('click',async()=>{await signOut(auth);window.location.href='index.html';});
        }else{
            links+=`<a href="checkout.html" class="nav-link">Cart <span id="cart-badge"></span></a><a href="auth.html" class="nav-link">Login</a>`;
            nav.innerHTML=`<a href="index.html" class="nav-brand">🪴 Verdant</a><div class="nav-links">${links}</div>`;
        }
        updateCartBadge();
    });
}

async function initIndex(){
    const grid=document.getElementById('featured-grid');if(!grid)return;
    try{
        const q=query(collection(db,'plants'),limit(3));const snap=await getDocs(q);
        console.log('Data fetched - Landing Page');
        grid.innerHTML='';
        if(snap.empty){grid.innerHTML=`<p style="grid-column:1/-1;text-align:center;">No plants available.</p>`;return;}
        snap.forEach(d=>{
            const p={id:d.id,...d.data()};
            grid.innerHTML+=`<div class="card"><a href="product.html?id=${p.id}"><img src="${p.image}" alt="${p.name}" loading="lazy" onerror="this.src='https://placehold.co/400x280/e0e0e0/2d5a27?text=Leaf'"></a><div class="card-content"><h3 class="card-title">${p.name}</h3><div class="card-price">$${p.price.toFixed(2)}</div></div></div>`;
        });
    }catch(e){console.error(e);grid.innerHTML=`<p style="color:red;grid-column:1/-1;text-align:center;">Error loading features.</p>`;}
}

async function initProducts(){
    const grid=document.getElementById('plants-grid');const filters=document.getElementById('filters');if(!grid)return;
    let allP=[];let curF='all';
    
    // Skeleton Loaders String
    const skeletonHTML = Array(6).fill(`<div class="card skeleton-card" style="height:350px; background:#e0e0e0; animation: pulse 1.5s infinite ease-in-out;"></div>`).join('');
    grid.innerHTML = skeletonHTML;

    filters.addEventListener('click',e=>{
        if(e.target.classList.contains('filter-btn')){
            document.querySelectorAll('.filter-btn').forEach(b=>b.classList.remove('active'));
            e.target.classList.add('active');curF=e.target.getAttribute('data-filter');
            renderP();
        }
    });
    
    // Pagination & Limit Optimization: Fetch top 10 first using getDocs instead of onSnapshot
    try {
        const q=query(collection(db,'plants'), limit(10));
        const snap=await getDocs(q);
        console.log('Data fetched - Products');
        allP = snap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        renderP();
    } catch(err) {
        console.error("Error fetching plants: ", err);
        grid.innerHTML = `<p style="grid-column:1/-1;text-align:center;color:red;">Error loading plants.</p>`;
    }
    
    function renderP(){
        grid.innerHTML='';
        const fil=curF==='all'?allP:allP.filter(p=>{const c=Array.isArray(p.category)?p.category:[p.category];return c.includes(curF);});
        if(fil.length===0){grid.innerHTML=`<p style="grid-column:1/-1;text-align:center;">No plants found matching filter.</p>`;return;}
        fil.forEach(p=>{
            const av=Math.max(0,p.stock-(p.sold||0));const os=av===0;
            const c=document.createElement('div');c.className='card';
            c.innerHTML=`<a href="product.html?id=${p.id}"><img src="${p.image}" alt="${p.name}" loading="lazy" onerror="this.src='https://placehold.co/400x280/e0e0e0/2d5a27?text=Leaf'"></a><div class="card-content"><div class="card-tags">${(Array.isArray(p.category)?p.category:[p.category]).map(t=>`<span class="tag">${t.replace('-',' ')}</span>`).join('')}</div><h3 class="card-title">${p.name}</h3><div class="card-price">$${p.price.toFixed(2)}</div><div class="card-stock" style="color:${os?'red':'var(--primary)'}">${os?'Out of Stock':`${av} left in stock`}</div><button class="btn-primary add-to-cart" data-id="${p.id}" ${os?'disabled':''}>${os?'Out of Stock':'Add to Cart'}</button></div>`;
            grid.appendChild(c);
            const btn=c.querySelector('.add-to-cart');
            btn.addEventListener('click',()=>{btn.textContent='Adding...';btn.disabled=true;setTimeout(()=>{addToLocalCart(p,1);btn.textContent='Added ✔';setTimeout(()=>{btn.textContent='Add to Cart';btn.disabled=false;},1000);},300);});
        });
        // We added a simple Load More button since we limited to 10
        if(allP.length === 10) {
            const moreBtn = document.createElement('button');
            moreBtn.className = 'btn-primary';
            moreBtn.style="grid-column:1/-1; width:auto; margin: 0 auto; display:block;";
            moreBtn.textContent = 'Load All (No Limit Simulation)';
            moreBtn.onclick = async () => {
                const snap2 = await getDocs(collection(db,'plants')); // Load all
                allP = snap2.docs.map(doc => ({ id: doc.id, ...doc.data() }));
                renderP();
            };
            grid.appendChild(moreBtn);
        }
    }
}

async function initProductDetail(){
    const con=document.getElementById('product-container');if(!con)return;
    const pid=new URLSearchParams(window.location.search).get('id');
    if(!pid){con.innerHTML=`<p style="grid-column:1/-1;color:red;text-align:center;">No ID.</p>`;return;}
    
    // Skeleton
    con.innerHTML = `<div class="skeleton-card" style="height:500px; background:#e0e0e0; animation: pulse 1.5s infinite; border-radius:16px;"></div><div class="skeleton-card" style="height:300px; background:#e0e0e0; animation: pulse 1.5s infinite; border-radius:16px;"></div>`;
    
    try{
        const ds=await getDoc(doc(db,'plants',pid));
        if(!ds.exists()){con.innerHTML=`<p>Not found.</p>`;return;}
        const p={id:ds.id,...ds.data()};const av=Math.max(0,p.stock-(p.sold||0));const cats=Array.isArray(p.category)?p.category:[p.category];const os=av===0;
        con.innerHTML=`<div><img src="${p.image}" alt="${p.name}" loading="lazy" style="width:100%;border-radius:16px;object-fit:cover;height:500px;"></div><div style="display:flex;flex-direction:column;gap:1.5rem;"><div class="card-tags">${cats.map(c=>`<span class="tag">${c.replace('-',' ')}</span>`).join('')}</div><h1 style="font-size:2.5rem;color:var(--primary);">${p.name}</h1><div style="font-size:1.8rem;font-weight:700;">$${p.price.toFixed(2)}</div><div style="color:${os?'red':'#555'}">${os?'Out of Stock':`${av} available`}</div><div style="background:var(--surface);padding:1.5rem;border-radius:12px;border:1px solid var(--border);"><h3>Care</h3><p>${p.careInstructions||'Keep in bright indirect light.'}</p></div><div class="qty-controls" style="width:fit-content;padding:0.5rem;background:var(--surface);border:1px solid var(--border);border-radius:8px;"><button class="qty-btn" id="btn-dec" style="width:35px;height:35px;border:none;">-</button><span id="qty-val" style="width:40px;text-align:center;font-weight:600;">1</span><button class="qty-btn" id="btn-inc" style="width:35px;height:35px;border:none;" ${av<=1?'disabled':''}>+</button></div><button id="add-to-cart-btn" class="btn-primary" style="padding:1rem;border-radius:50px;" ${os?'disabled':''}>${os?'Out of Stock':'Add to Cart'}</button></div>`;
        if(!os){
            let q=1;const bd=document.getElementById('btn-dec'),bi=document.getElementById('btn-inc'),qv=document.getElementById('qty-val'),ab=document.getElementById('add-to-cart-btn');
            bd.disabled=true;
            bd.onclick=()=>{if(q>1){q--;qv.textContent=q;bi.disabled=false;if(q===1)bd.disabled=true;}};
            bi.onclick=()=>{if(q<av){q++;qv.textContent=q;bd.disabled=false;if(q>=av)bi.disabled=true;}};
            ab.onclick=()=>{ab.textContent='Adding...';ab.disabled=true;setTimeout(()=>{addToLocalCart(p,q);ab.textContent='Added ✔';setTimeout(()=>{ab.textContent='Add to Cart';ab.disabled=false;q=1;qv.textContent='1';bd.disabled=true;bi.disabled=av<=1;},1500);},400);};
        }
    }catch(e){console.error(e);con.innerHTML=`<p>Error.</p>`;}
}

function initCheckout(){
    const con=document.getElementById('cart-container'),sb=document.getElementById('subtotal'),tl=document.getElementById('total'),cb=document.getElementById('checkout-btn'),sm=document.getElementById('success-modal');
    if(!con)return;
    function rC(){
        const c=getLocalCart();if(c.length===0){con.innerHTML=`<div style="padding:3rem;text-align:center;"><p>Cart is empty.</p></div>`;cb.disabled=true;sb.textContent='$0.00';tl.textContent='$0.00';return;}
        con.innerHTML='';let st=0;
        c.forEach((i,idx)=>{
            st+=i.price*i.qty;
            con.innerHTML+=`<div class="cart-item"><img src="${i.image}" loading="lazy" alt="${i.name}"><div class="cart-item-details"><h3>${i.name}</h3><p>$${i.price.toFixed(2)}</p></div><div class="qty-controls"><button class="qty-btn dec-btn" data-index="${idx}">-</button><span>${i.qty}</span><button class="qty-btn inc-btn" data-index="${idx}">+</button></div><div style="font-weight:700;">$${(i.price*i.qty).toFixed(2)}</div><button class="rm-btn" data-index="${idx}" style="background:none;color:red;font-size:1.5rem;border:none;">&times;</button></div>`;
        });
        sb.textContent=`$${st.toFixed(2)}`;tl.textContent=`$${st.toFixed(2)}`;cb.disabled=false;
        document.querySelectorAll('.dec-btn').forEach(b=>b.onclick=e=>{const x=e.target.dataset.index;if(c[x].qty>1){c[x].qty--;saveLocalCart(c);rC();}});
        document.querySelectorAll('.inc-btn').forEach(b=>b.onclick=e=>{const x=e.target.dataset.index;c[x].qty++;saveLocalCart(c);rC();});
        document.querySelectorAll('.rm-btn').forEach(b=>b.onclick=e=>{c.splice(e.target.dataset.index,1);saveLocalCart(c);rC();});
    }
    rC();
    cb.onclick=async()=>{
        const c=getLocalCart();if(c.length===0)return;
        cb.disabled=true;cb.textContent='Processing...';
        try{
            for(const i of c){await updateDoc(doc(db,'plants',i.id),{stock:increment(-i.qty),sold:increment(i.qty)});}
            setTimeout(()=>{clearLocalCart();rC();sm.style.display='flex';},1000);
        }catch(err){console.error(err);alert('Error processing.');cb.disabled=false;cb.textContent='Pay Securely';}
    };
    document.getElementById('continue-btn').onclick=()=>window.location.href='products.html';
}

function initAdmin(){
    const tb=document.getElementById('inventory-tbody');if(!tb)return;
    let inv=[];
    onSnapshot(collection(db,'plants'),snap=>{
        inv=snap.docs.map(d=>({id:d.id,...d.data()}));
        tb.innerHTML='';if(inv.length===0){tb.innerHTML=`<tr><td colspan="6" style="text-align:center;">No inventory.</td></tr>`;return;}
        inv.forEach(p=>{
            const av=Math.max(0,p.stock-(p.sold||0));const cs=Array.isArray(p.category)?p.category.join(', '):p.category;
            tb.innerHTML+=`<tr><td><img src="${p.image}" loading="lazy" alt="${p.name}" style="width:50px;height:50px;object-fit:cover;"></td><td>${p.name}</td><td>${cs}</td><td>$${p.price.toFixed(2)}</td><td style="color:${av<=5?'red':'inherit'}">${av}</td><td style="text-align:right;"><button class="btn-primary update-btn" data-id="${p.id}" data-current="${p.stock}" style="padding:0.4rem;font-size:0.8rem;width:auto;">Update</button> <button class="btn-danger delete-btn" data-id="${p.id}">Del</button></td></tr>`;
        });
        document.querySelectorAll('.update-btn').forEach(b=>b.onclick=async e=>{
            const id=e.target.dataset.id;const cr=e.target.dataset.current;const ns=prompt("New absolute stock:",cr);
            if(ns!==null&&ns.trim()!==""){
                const nsv=parseInt(ns,10);if(!isNaN(nsv)&&nsv>=0)try{await updateDoc(doc(db,'plants',id),{stock:nsv,sold:0});}catch(e){console.error(e);}
            }
        });
        document.querySelectorAll('.delete-btn').forEach(b=>b.onclick=async e=>{if(confirm("Delete plant?"))try{await deleteDoc(doc(db,'plants',e.target.dataset.id));}catch(err){console.error(err);}});
    });
}

function initAddPlant(){
    const fm=document.getElementById('add-plant-form');if(!fm)return;
    fm.onsubmit=async e=>{
        e.preventDefault();const sBtn=document.getElementById('submit-btn');const msg=document.getElementById('status-msg');
        sBtn.disabled=true;sBtn.textContent='Adding...';msg.textContent='';
        const n=document.getElementById('p-name').value.trim(),p=parseFloat(document.getElementById('p-price').value),c=Array.from(document.getElementById('p-category').selectedOptions).map(o=>o.value),i=document.getElementById('p-image').value.trim(),ca=document.getElementById('p-care').value.trim();
        if(!n||isNaN(p)||c.length===0||!i||!ca){msg.textContent='Fill correctly.';msg.style.color='red';sBtn.disabled=false;sBtn.textContent='Add Plant';return;}
        try{await addDoc(collection(db,'plants'),{name:n,price:p,category:c,image:i,careInstructions:ca,stock:20,sold:0});msg.textContent='Plant Added! Initial Stock 20.';msg.style.color='var(--primary)';fm.reset();}catch(err){console.error(err);msg.textContent='Error.';msg.style.color='red';}
        sBtn.disabled=false;sBtn.textContent='Add Plant';
    };
}

// Global Init
document.addEventListener('DOMContentLoaded', () => {
    setupNavbar();
    const p = window.location.pathname;
    if(p.endsWith('/') || p.endsWith('index.html')) initIndex();
    else if(p.endsWith('products.html')) initProducts();
    else if(p.endsWith('product.html')) initProductDetail();
    else if(p.endsWith('checkout.html') || p.endsWith('cart.html')) initCheckout();
    else if(p.endsWith('admin.html')) initAdmin();
    else if(p.endsWith('add-plant.html')) initAddPlant();
});
